  8→import { useVideoUpload } from "@/hooks/useVideoUpload";
  9→import { apiFetch } from "@/lib/api";
 10→import type { Candidate } from "@rearden/types";
 11→import styles from "./Register.module.scss";
 12→
 13→export function Register() {
 14→  const navigate = useNavigate();
 15→  const { upload, uploading, progress, previewUrl } = useVideoUpload();
 16→  const [submitting, setSubmitting] = useState(false);
 17→  const [form, setForm] = useState({
 18→    name: "",
 19→    email: "",
 20→    title: "",
 21→    location: "",
 22→    bio: "",
 23→    skills: "",
 24→    experience: "",
 25→  });
 26→
 27→  const updateField = (field: string) => (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
 28→    setForm((prev) => ({ ...prev, [field]: e.target.value }));
 29→  };
 30→
 31→  const [videoUrl, setVideoUrl] = useState<string | null>(null);
 32→
 33→  const handleVideoUpload = async (file: File) => {
 34→    try {
 35→      const url = await upload(file);
 36→      setVideoUrl(url);
 37→    } catch {
 38→      // upload error handled by hook
 39→    }
 40→  };
 41→
 42→  const handleSubmit = async (e: React.FormEvent) => {
 43→    e.preventDefault();
 44→    setSubmitting(true);
 45→
 46→    try {
 47→      const response = await apiFetch<{ success: boolean; data: Candidate }>(
 48→        "/candidates",
 49→        {
 50→          method: "POST",
 51→          body: JSON.stringify({
 52→            name: form.name,
 53→            email: form.email,
 54→            title: form.title,
 55→            location: form.location,
 56→            bio: form.bio,
 57→            skills: form.skills.split(",").map((s) => s.trim()).filter(Boolean),
 58→            experience: parseInt(form.experience) || 0,
 59→            videoUrl,
 60→            availability: "immediate",
 61→          }),
 62→        }
 63→      );
 64→
 65→      navigate(`/candidate/${response.data.id}`);
 66→    } catch {
 67→      setSubmitting(false);
 68→    }
 69→  };
 70→
 71→  return (
 72→    <div className={styles.register}>
 73→        <motion.div
 74→          className={styles.header}
 75→          initial={{ opacity: 0, y: 20 }}
 76→          animate={{ opacity: 1, y: 0 }}
 77→          transition={{ duration: 0.5 }}
 78→        >
 79→          <h1 className={styles.title}>Join Rearden</h1>
 80→          <p className={styles.subtitle}>
 81→            Create your video profile and get discovered by top recruiters
 82→          </p>
 83→        </motion.div>
 84→
 85→        <motion.form
 86→          className={styles.form}
 87→          onSubmit={handleSubmit}
 88→          initial={{ opacity: 0, y: 20 }}
 89→          animate={{ opacity: 1, y: 0 }}
 90→          transition={{ duration: 0.5, delay: 0.15 }}
 91→        >
 92→          <div className={styles.formGrid}>
 93→            <Input
 94→              label="Full Name"
 95→              placeholder="John Doe"
 96→              value={form.name}
 97→              onChange={updateField("name")}
 98→            />
 99→            <Input
100→              label="Email"
101→              type="email"
102→              placeholder="john@example.com"
103→              value={form.email}
104→              onChange={updateField("email")}
105→            />
106→            <Input
107→              label="Job Title"
108→              placeholder="Senior Frontend Engineer"
109→              value={form.title}
110→              onChange={updateField("title")}
111→            />
112→            <Input
113→              label="Location"
114→              placeholder="San Francisco, CA"
115→              value={form.location}
116→              onChange={updateField("location")}
117→            />
118→            <Input
119→              label="Years of Experience"
120→              type="number"
121→              placeholder="5"
122→              value={form.experience}
123→              onChange={updateField("experience")}
124→            />
125→            <Input
126→              label="Skills (comma separated)"
127→              placeholder="React, TypeScript, Node.js"
128→              value={form.skills}
129→              onChange={updateField("skills")}
130→            />
131→          </div>
132→
133→          <div className={styles.bioField}>
134→            <label className={styles.label}>Bio</label>
135→            <textarea
136→              className={styles.textarea}
137→              placeholder="Tell recruiters about yourself, your experience, and what you're looking for..."
138→              value={form.bio}
139→              onChange={updateField("bio")}
140→              rows={4}
141→            />
142→          </div>
143→
144→          <div className={styles.videoSection}>
145→            <label className={styles.label}>Video Introduction</label>
146→            <p className={styles.videoHint}>
147→              Record a 1-2 minute video introducing yourself
148→            </p>
149→            <VideoUpload
150→              onUpload={handleVideoUpload}
151→              uploading={uploading}
152→              progress={progress}
153→              previewUrl={previewUrl ?? undefined}
154→            />
155→          </div>
156→
157→          <div className={styles.actions}>
158→            <Button
159→              variant="primary"
160→              size="lg"
161→              type="submit"
162→              disabled={submitting || !form.name || !form.email}
163→            >
164→              {submitting ? "Creating Profile..." : "Create Profile"}
165→            </Button>
166→          </div>
167→        </motion.form>
168→    </div>
169→  );
170→}
