  1→import { useRef, useState } from "react";
  2→import { VideoPlayer } from "@/components/VideoPlayer/VideoPlayer";
  3→import styles from "./VideoUpload.module.scss";
  4→
  5→interface VideoUploadProps {
  6→  onUpload: (file: File) => void;
  7→  uploading?: boolean;
  8→  progress?: number;
  9→  previewUrl?: string;
 10→}
 11→
 12→export function VideoUpload({
 13→  onUpload,
 14→  uploading,
 15→  progress = 0,
 16→  previewUrl,
 17→}: VideoUploadProps) {
 18→  const [isDragging, setIsDragging] = useState(false);
 19→  const inputRef = useRef<HTMLInputElement>(null);
 20→
 21→  const handleDragOver = (e: React.DragEvent) => {
 22→    e.preventDefault();
 23→    setIsDragging(true);
 24→  };
 25→
 26→  const handleDragLeave = () => {
 27→    setIsDragging(false);
 28→  };
 29→
 30→  const handleDrop = (e: React.DragEvent) => {
 31→    e.preventDefault();
 32→    setIsDragging(false);
 33→
 34→    const file = e.dataTransfer.files[0];
 35→    if (file && file.type.startsWith("video/")) {
 36→      onUpload(file);
 37→    }
 38→  };
 39→
 40→  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
 41→    const file = e.target.files?.[0];
 42→    if (file) {
 43→      onUpload(file);
 44→    }
 45→  };
 46→
 47→  const handleClick = () => {
 48→    inputRef.current?.click();
 49→  };
 50→
 51→  if (previewUrl) {
 52→    return (
 53→      <div className={styles.preview}>
 54→        <VideoPlayer src={previewUrl} />
 55→        <button className={styles.reupload} onClick={handleClick}>
 56→          Re-upload
 57→        </button>
 58→        <input
 59→          ref={inputRef}
 60→          type="file"
 61→          accept="video/*"
 62→          onChange={handleFileSelect}
 63→          className={styles.hiddenInput}
 64→        />
 65→      </div>
 66→    );
 67→  }
 68→
 69→  return (
 70→    <div
 71→      className={`${styles.dropzone} ${isDragging ? styles.dragging : ""}`}
 72→      onDragOver={handleDragOver}
 73→      onDragLeave={handleDragLeave}
 74→      onDrop={handleDrop}
 75→      onClick={handleClick}
 76→      role="button"
 77→      tabIndex={0}
 78→    >
 79→      <input
 80→        ref={inputRef}
 81→        type="file"
 82→        accept="video/*"
 83→        onChange={handleFileSelect}
 84→        className={styles.hiddenInput}
 85→      />
 86→
 87→      {uploading ? (
 88→        <div className={styles.uploading}>
 89→          <div className={styles.progressBar}>
 90→            <div
 91→              className={styles.progressFill}
 92→              style={{ width: `${progress}%` }}
 93→            />
 94→          </div>
 95→          <p className={styles.progressText}>{Math.round(progress)}%</p>
 96→        </div>
 97→      ) : (
 98→        <>
 99→          <svg
100→            className={styles.icon}
101→            width="48"
102→            height="48"
103→            viewBox="0 0 24 24"
104→            fill="none"
105→            stroke="currentColor"
106→            strokeWidth="2"
107→          >
108→            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
109→            <polyline points="17 8 12 3 7 8" />
110→            <line x1="12" y1="3" x2="12" y2="15" />
111→          </svg>
112→          <p className={styles.text}>Drag & drop or click to upload</p>
113→          <p className={styles.hint}>Video files only</p>
114→        </>
115→      )}
116→    </div>
117→  );
118→}
