 3→import { useSound } from "@/hooks/useSound";
 4→import styles from "./Button.module.scss";
 5→
 6→interface ButtonProps {
 7→  variant?: "primary" | "secondary" | "ghost";
 8→  size?: "sm" | "md" | "lg";
 9→  children: ReactNode;
10→  className?: string;
11→  href?: string;
12→  disabled?: boolean;
13→  onClick?: () => void;
14→  type?: "button" | "submit" | "reset";
15→}
16→
17→export function Button({
18→  variant = "primary",
19→  size = "md",
20→  children,
21→  className,
22→  href,
23→  disabled,
24→  onClick,
25→  type = "button",
26→}: ButtonProps) {
27→  const { playSound } = useSound();
28→
29→  const classNames = [
30→    styles.button,
31→    styles[variant],
32→    styles[size],
33→    className,
34→  ]
35→    .filter(Boolean)
36→    .join(" ");
37→
38→  const handleClick = () => {
39→    playSound("click");
40→    onClick?.();
41→  };
42→
43→  const motionProps = {
44→    whileHover: { scale: 1.02 },
45→    whileTap: { scale: 0.95, y: 2 },
46→    transition: { type: "spring" as const, stiffness: 400, damping: 25 },
47→  };
48→
49→  if (href) {
50→    return (
51→      <motion.a
